      SUBROUTINE Type3_WTG_AvgOut()

!---------------------------------------
! Standard includes
!---------------------------------------

      INCLUDE 'nd.h'
      INCLUDE 'emtconst.h'
      INCLUDE 'emtstor.h'
      INCLUDE 's0.h'
      INCLUDE 's1.h'
      INCLUDE 's2.h'
      INCLUDE 's4.h'
      INCLUDE 'branches.h'
      INCLUDE 'pscadv3.h'
      INCLUDE 'fnames.h'
      INCLUDE 'radiolinks.h'
      INCLUDE 'matlab.h'
      INCLUDE 'rtconfig.h'

!---------------------------------------
! Function/Subroutine Declarations
!---------------------------------------

      REAL    EMTDC_VVDC    ! 
      REAL    P3PH3         ! 
      REAL    Q3PH3         ! 
!     SUBR    DGTL_RMS3     ! '3 Phase Digital RMS Meter'
!     SUBR    MPHASE3PS     ! Phase Measurement in a 3p signal
!     SUBR    SynchronizationOut  ! 
      REAL    VBRANCH       ! 
!     SUBR    WindTurbine_MechModelOut  ! 
!     SUBR    DFIG_Converters_AvgOut  ! 

!---------------------------------------
! Variable Declarations
!---------------------------------------


! Electrical Node Indices
      INTEGER  NT_3(3), NT_5(3), NT_9(3)
      INTEGER  NT_11(3)

! Control Signals
      REAL     VI_m(15), Iabc(3), Vrms_pu
      REAL     Vrms_bus, PG, T2Dblk, Vpcc(3)
      REAL     I_trm(3), Vst1(3), Vst2(3)
      REAL     Istator(3), RT_6, QG, TRNR
      REAL     V_nom_gen, Rs_pu, V_nom_con
      REAL     Vdc_Base, I_max, Vrms_bus2
      REAL     PhaseMach, I_Machine(3), V1rms_pu
      REAL     PhaseTrf, PG_PCC, QG_PCC

! Internal Variables
      INTEGER  IVD1_1
      REAL     RVD1_1, RVD1_2, RVD1_3, RVD1_4

! Indexing variables
      INTEGER ICALL_NO                            ! Module call num
      INTEGER ISTOL, ISTOI, ISTOF, ISTOC, IT_0    ! Storage Indices
      INTEGER IPGB                                ! Control/Monitoring
      INTEGER ISUBS, SS(1), IBRCH(1), INODE       ! SS/Node/Branch/Xfmr
      INTEGER IXFMR


!---------------------------------------
! Local Indices
!---------------------------------------

! Dsdyn <-> Dsout transfer index storage

      NTXFR = NTXFR + 1

      ISTOL = TXFR(NTXFR,1)
      ISTOI = TXFR(NTXFR,2)
      ISTOF = TXFR(NTXFR,3)
      ISTOC = TXFR(NTXFR,4)

! Increment and assign runtime configuration call indices

      ICALL_NO  = NCALL_NO
      NCALL_NO  = NCALL_NO + 1

! Increment global storage indices

      IPGB      = NPGB
      NPGB      = NPGB + 25
      NCX       = NCX + 0
      INODE     = NNODE + 2
      NNODE     = NNODE + 36
      IXFMR     = NXFMR
      NXFMR     = NXFMR + 3
      NCSCS     = NCSCS + 0
      NCSCR     = NCSCR + 0

! Initialize Subsystem Mapping

      ISUBS = NSUBS + 0
      NSUBS = NSUBS + 1

      DO IT_0 = 1,1
         SS(IT_0) = SUBS(ISUBS + IT_0)
      END DO

! Initialize Branch Mapping.

      IBRCH(1)     = NBRCH(SS(1))
      NBRCH(SS(1)) = NBRCH(SS(1)) + 49
!---------------------------------------
! Transfers from storage arrays
!---------------------------------------

      Vrms_pu  = STOF(ISTOF + 43)
      Vrms_bus = STOF(ISTOF + 47)
      PG       = STOF(ISTOF + 48)
      T2Dblk   = STOF(ISTOF + 49)
      RT_6     = STOF(ISTOF + 72)
      QG       = STOF(ISTOF + 74)
      TRNR     = STOF(ISTOF + 75)
      V_nom_gen = STOF(ISTOF + 76)
      Rs_pu    = STOF(ISTOF + 77)
      V_nom_con = STOF(ISTOF + 78)
      Vdc_Base = STOF(ISTOF + 79)
      I_max    = STOF(ISTOF + 80)
      Vrms_bus2 = STOF(ISTOF + 81)
      PhaseMach = STOF(ISTOF + 82)
      V1rms_pu = STOF(ISTOF + 86)
      PhaseTrf = STOF(ISTOF + 87)
      PG_PCC   = STOF(ISTOF + 88)
      QG_PCC   = STOF(ISTOF + 89)

! Array (1:3) quantities...
      DO IT_0 = 1,3
         Iabc(IT_0) = STOF(ISTOF + 38 + IT_0)
         Vpcc(IT_0) = STOF(ISTOF + 50 + IT_0)
         I_trm(IT_0) = STOF(ISTOF + 53 + IT_0)
         Vst1(IT_0) = STOF(ISTOF + 56 + IT_0)
         Vst2(IT_0) = STOF(ISTOF + 59 + IT_0)
         Istator(IT_0) = STOF(ISTOF + 62 + IT_0)
         I_Machine(IT_0) = STOF(ISTOF + 82 + IT_0)
      END DO

! Array (1:15) quantities...
      DO IT_0 = 1,15
         VI_m(IT_0) = STOF(ISTOF + 20 + IT_0)
      END DO


!---------------------------------------
! Electrical Node Lookup
!---------------------------------------


! Array (1:3) quantities...
      DO IT_0 = 1,3
         NT_3(IT_0) = NODE(INODE + 9 + IT_0)
         NT_5(IT_0) = NODE(INODE + 15 + IT_0)
         NT_9(IT_0) = NODE(INODE + 25 + IT_0)
         NT_11(IT_0) = NODE(INODE + 31 + IT_0)
      END DO

!---------------------------------------
! Configuration of Models
!---------------------------------------

      IF ( TIMEZERO ) THEN
         FILENAME = 'Type3_WTG_Avg.dta'
         CALL EMTDC_OPENFILE
         SECTION = 'DATADSO:'
         CALL EMTDC_GOTOSECTION
      ENDIF
!---------------------------------------
! Generated code from module definition
!---------------------------------------


! 60:[const] Real Constant 

      RT_6 = 1.0

! 140:[const] Real Constant 'VLL RMS'

      V_nom_con = 0.69

! 150:[const] Real Constant 'pu'

      Rs_pu = 0.0054

! 160:[const] Real Constant 'VLL RMS'

      V_nom_gen = 0.9

! 170:[const] Real Constant 'Turn Ratio'

      TRNR = 0.391

! 180:[const] Real Constant '[kV]'

      Vdc_Base = 1.45

! 190:[const] Real Constant 'maximum current of converters [pu]'

      I_max = 1.2

! 200:[multimeter] Multimeter 
      IVD1_1 = NRTCF
      NRTCF  = NRTCF + 5
      Vpcc(1) = EMTDC_VVDC(SS(1), NT_11(1), 0)
      Vpcc(2) = EMTDC_VVDC(SS(1), NT_11(2), 0)
      Vpcc(3) = EMTDC_VVDC(SS(1), NT_11(3), 0)
      RVD1_1 = RTCF(IVD1_1) * P3PH3(SS(1), (IBRCH(1)+22), (IBRCH(1)+23),&
     & (IBRCH(1)+24),RTCF(IVD1_1+2),0)
      IF (UPDATE_AG) CALL PSCAD_AGRG2(ICALL_NO,400202499,RVD1_1,"Pd")
      PG_PCC = RVD1_1
      RVD1_1 = RTCF(IVD1_1) * Q3PH3(SS(1), (IBRCH(1)+22), (IBRCH(1)+23),&
     & (IBRCH(1)+24),RTCF(IVD1_1+2),0)
      IF (UPDATE_AG) CALL PSCAD_AGRG2(ICALL_NO,400202499,RVD1_1,"Qd")
      QG_PCC = RVD1_1
      CALL DGTL_RMS3(256,SS(1),NT_11(1),NT_11(2),NT_11(3),RTCF(IVD1_1+3)&
     &,1.0,0.0,RVD1_1)
      RVD1_1 = RTCF(IVD1_1+1)*RVD1_1
      IF (UPDATE_AG) CALL PSCAD_AGRG2(ICALL_NO,400202499,RVD1_1,"Vd")
      Vrms_bus = RVD1_1
      IF (FIRSTSTEP) THEN
        CALL PSCAD_AGI2(ICALL_NO,400202499,1,"hide1")
        CALL PSCAD_AGI2(ICALL_NO,400202499,1,"hide2")
      ENDIF

! 220:[multimeter] Multimeter 
      IVD1_1 = NRTCF
      NRTCF  = NRTCF + 5
      I_trm(1) = ( CBR((IBRCH(1)+25), SS(1)))
      I_trm(2) = ( CBR((IBRCH(1)+26), SS(1)))
      I_trm(3) = ( CBR((IBRCH(1)+27), SS(1)))
      RVD1_1 = RTCF(IVD1_1) * P3PH3(SS(1), (IBRCH(1)+25), (IBRCH(1)+26),&
     & (IBRCH(1)+27),RTCF(IVD1_1+2),0)
      IF (UPDATE_AG) CALL PSCAD_AGRG2(ICALL_NO,110892719,RVD1_1,"Pd")
      PG = RVD1_1
      RVD1_1 = RTCF(IVD1_1) * Q3PH3(SS(1), (IBRCH(1)+25), (IBRCH(1)+26),&
     & (IBRCH(1)+27),RTCF(IVD1_1+2),0)
      IF (UPDATE_AG) CALL PSCAD_AGRG2(ICALL_NO,110892719,RVD1_1,"Qd")
      QG = RVD1_1
      CALL DGTL_RMS3(256,SS(1),NT_5(1),NT_5(2),NT_5(3),RTCF(IVD1_1+3),1.&
     &0,0.0,RVD1_1)
      RVD1_1 = RTCF(IVD1_1+1)*RVD1_1
      IF (UPDATE_AG) CALL PSCAD_AGRG2(ICALL_NO,110892719,RVD1_1,"Vd")
      Vrms_bus2 = RVD1_1
      IF (FIRSTSTEP) THEN
        CALL PSCAD_AGI2(ICALL_NO,110892719,1,"hide1")
        CALL PSCAD_AGI2(ICALL_NO,110892719,1,"hide2")
      ENDIF

! 240:[multimeter] Multimeter 
      IVD1_1 = NRTCF
      NRTCF  = NRTCF + 5
      I_Machine(1) = ( CBR((IBRCH(1)+46), SS(1)))
      I_Machine(2) = ( CBR((IBRCH(1)+47), SS(1)))
      I_Machine(3) = ( CBR((IBRCH(1)+48), SS(1)))
      Vst1(1) = EMTDC_VVDC(SS(1), NT_3(1), 0)
      Vst1(2) = EMTDC_VVDC(SS(1), NT_3(2), 0)
      Vst1(3) = EMTDC_VVDC(SS(1), NT_3(3), 0)
      CALL DGTL_RMS3(256,SS(1),NT_3(1),NT_3(2),NT_3(3),RTCF(IVD1_1+3),1.&
     &0,0.0,RVD1_1)
      RVD1_1 = RTCF(IVD1_1+1)*RVD1_1
      IF (UPDATE_AG) CALL PSCAD_AGRG2(ICALL_NO,250021991,RVD1_1,"Vd")
      V1rms_pu = RVD1_1
      RVD1_2 = EMTDC_VVDC(SS(1), NT_3(1), 0)
      RVD1_3 = EMTDC_VVDC(SS(1), NT_3(2), 0)
      RVD1_4 = EMTDC_VVDC(SS(1), NT_3(3), 0)
      CALL MPHASE3PS(1, 1, RVD1_2, RVD1_3, RVD1_4, RTCF(IVD1_1+2), RTCF(&
     &IVD1_1+3) , RVD1_1)
      PhaseTrf = RVD1_1
      IF (FIRSTSTEP) THEN
        CALL PSCAD_AGI2(ICALL_NO,250021991,1,"hide1")
        CALL PSCAD_AGI2(ICALL_NO,250021991,1,"hide2")
      ENDIF

! 250:[multimeter] Multimeter 
      IVD1_1 = NRTCF
      NRTCF  = NRTCF + 5
      Iabc(1) = ( CBR((IBRCH(1)+28), SS(1)))
      Iabc(2) = ( CBR((IBRCH(1)+29), SS(1)))
      Iabc(3) = ( CBR((IBRCH(1)+30), SS(1)))
      Vst2(1) = EMTDC_VVDC(SS(1), NT_9(1), 0)
      Vst2(2) = EMTDC_VVDC(SS(1), NT_9(2), 0)
      Vst2(3) = EMTDC_VVDC(SS(1), NT_9(3), 0)
      RVD1_1 = RTCF(IVD1_1) * P3PH3(SS(1), (IBRCH(1)+28), (IBRCH(1)+29),&
     & (IBRCH(1)+30),RTCF(IVD1_1+2),0)
      IF (UPDATE_AG) CALL PSCAD_AGRG2(ICALL_NO,1335436371,RVD1_1,"Pd")
      RVD1_1 = RTCF(IVD1_1) * Q3PH3(SS(1), (IBRCH(1)+28), (IBRCH(1)+29),&
     & (IBRCH(1)+30),RTCF(IVD1_1+2),0)
      IF (UPDATE_AG) CALL PSCAD_AGRG2(ICALL_NO,1335436371,RVD1_1,"Qd")
      CALL DGTL_RMS3(256,SS(1),NT_9(1),NT_9(2),NT_9(3),RTCF(IVD1_1+3),1.&
     &0,0.0,RVD1_1)
      RVD1_1 = RTCF(IVD1_1+1)*RVD1_1
      IF (UPDATE_AG) CALL PSCAD_AGRG2(ICALL_NO,1335436371,RVD1_1,"Vd")
      Vrms_pu = RVD1_1
      RVD1_2 = EMTDC_VVDC(SS(1), NT_9(1), 0)
      RVD1_3 = EMTDC_VVDC(SS(1), NT_9(2), 0)
      RVD1_4 = EMTDC_VVDC(SS(1), NT_9(3), 0)
      CALL MPHASE3PS(1, 1, RVD1_2, RVD1_3, RVD1_4, RTCF(IVD1_1+2), RTCF(&
     &IVD1_1+3) , RVD1_1)
      PhaseMach = RVD1_1
      IF (FIRSTSTEP) THEN
        CALL PSCAD_AGI2(ICALL_NO,1335436371,1,"hide1")
        CALL PSCAD_AGI2(ICALL_NO,1335436371,1,"hide2")
      ENDIF

! 270:[ammeter] Current Meter 'Istator'
      Istator(1) = ( CBR((IBRCH(1)+43), SS(1)))
      Istator(2) = ( CBR((IBRCH(1)+44), SS(1)))
      Istator(3) = ( CBR((IBRCH(1)+45), SS(1)))

! 280:[const] Real Constant 

      T2Dblk = 0.2

! 330:[Synchronization]  
      CALL SynchronizationOut()


! 340:[pgb] Output Channel 'Vst1'

      DO IVD1_1 = 1, 3
         PGB(IPGB+1+IVD1_1-1) = Vst1(IVD1_1)
      ENDDO

! 350:[pgb] Output Channel 'Vst2'

      DO IVD1_1 = 1, 3
         PGB(IPGB+4+IVD1_1-1) = Vst2(IVD1_1)
      ENDDO

! 360:[pgb] Output Channel 'Vrms_pu'

      PGB(IPGB+7) = Vrms_pu

! 370:[pgb] Output Channel 'I_trm'

      DO IVD1_1 = 1, 3
         PGB(IPGB+8+IVD1_1-1) = I_trm(IVD1_1)
      ENDDO

! 380:[pgb] Output Channel 'Iabc'

      DO IVD1_1 = 1, 3
         PGB(IPGB+11+IVD1_1-1) = Iabc(IVD1_1)
      ENDDO

! 390:[pgb] Output Channel 'Vrms_bus'

      PGB(IPGB+14) = Vrms_bus

! 440:[datamerge] Merges data signals into an array 
      VI_m(1 : 3) = Vpcc
      VI_m(4 : 6) = I_trm
      VI_m(7 : 9) = Vst1
      VI_m(10 : 12) = Vst2
      VI_m(13 : 15) = Istator

! 460:[breaker3] 3 Phase Breaker 'BRK'
! Three Phase Breaker Currents
      CALL BRK_POWER(SS(1), (IBRCH(1)+1), (IBRCH(1)+2), (IBRCH(1)+3),0,0&
     &,0,IVD1_1,0.02,RVD1_1,RVD1_2)

! 550:[WindTurbine_MechModel]  
      CALL WindTurbine_MechModelOut()


! 690:[DFIG_Converters_Avg]  
      CALL DFIG_Converters_AvgOut()


!---------------------------------------
! Feedbacks and transfers to storage
!---------------------------------------

      STOF(ISTOF + 43) = Vrms_pu
      STOF(ISTOF + 47) = Vrms_bus
      STOF(ISTOF + 48) = PG
      STOF(ISTOF + 49) = T2Dblk
      STOF(ISTOF + 72) = RT_6
      STOF(ISTOF + 74) = QG
      STOF(ISTOF + 75) = TRNR
      STOF(ISTOF + 76) = V_nom_gen
      STOF(ISTOF + 77) = Rs_pu
      STOF(ISTOF + 78) = V_nom_con
      STOF(ISTOF + 79) = Vdc_Base
      STOF(ISTOF + 80) = I_max
      STOF(ISTOF + 81) = Vrms_bus2
      STOF(ISTOF + 82) = PhaseMach
      STOF(ISTOF + 86) = V1rms_pu
      STOF(ISTOF + 87) = PhaseTrf
      STOF(ISTOF + 88) = PG_PCC
      STOF(ISTOF + 89) = QG_PCC

! Array (1:3) quantities...
      DO IT_0 = 1,3
         STOF(ISTOF + 38 + IT_0) = Iabc(IT_0)
         STOF(ISTOF + 50 + IT_0) = Vpcc(IT_0)
         STOF(ISTOF + 53 + IT_0) = I_trm(IT_0)
         STOF(ISTOF + 56 + IT_0) = Vst1(IT_0)
         STOF(ISTOF + 59 + IT_0) = Vst2(IT_0)
         STOF(ISTOF + 62 + IT_0) = Istator(IT_0)
         STOF(ISTOF + 82 + IT_0) = I_Machine(IT_0)
      END DO

! Array (1:15) quantities...
      DO IT_0 = 1,15
         STOF(ISTOF + 20 + IT_0) = VI_m(IT_0)
      END DO


!---------------------------------------
! Close Model Data read
!---------------------------------------

      IF ( TIMEZERO ) CALL EMTDC_CLOSEFILE
      RETURN
      END

!=======================================================================

      SUBROUTINE Type3_WTG_AvgDyn_Begin(freq, VLL_Gr, No_WTG, Pbase,    &
     &   VRot_nom, Mrating, OMEG, Vw_nom, Slip_max, vWcutin, vWcutout)

!---------------------------------------
! Standard includes
!---------------------------------------

      INCLUDE 'nd.h'
      INCLUDE 'emtconst.h'
      INCLUDE 's0.h'
      INCLUDE 's1.h'
      INCLUDE 's4.h'
      INCLUDE 'branches.h'
      INCLUDE 'pscadv3.h'
      INCLUDE 'radiolinks.h'
      INCLUDE 'rtconfig.h'

!---------------------------------------
! Function/Subroutine Declarations
!---------------------------------------

!     SUBR    SynchronizationDyn_Begin  ! 
!     SUBR    WindTurbine_MechModelDyn_Begin  ! 
!     SUBR    DFIG_Converters_AvgDyn_Begin  ! 

!---------------------------------------
! Variable Declarations
!---------------------------------------


! Subroutine Arguments
      REAL,    INTENT(IN)  :: freq, VLL_Gr
      REAL,    INTENT(IN)  :: No_WTG, Pbase
      REAL,    INTENT(IN)  :: VRot_nom, Mrating
      REAL,    INTENT(IN)  :: OMEG, Vw_nom
      REAL,    INTENT(IN)  :: Slip_max, vWcutin
      REAL,    INTENT(IN)  :: vWcutout

! Electrical Node Indices
      INTEGER  NT_8(3), NT_11(3)

! Control Signals
      REAL     T2Dblk, RT_6, TRNR, V_nom_gen
      REAL     Rs_pu, V_nom_con, Vdc_Base, I_max

! Internal Variables
      INTEGER  IVD1_1
      REAL     RVD1_1, RVD1_2, RVD1_3, RVD1_4
      REAL     RVD1_5, RVD1_6, RVD1_7, RVD1_8
      REAL     RVD5_1(5), RVD12_1(12)
      REAL     RVD10_1(10), RVD10_2(10)
      REAL     RVD10_3(10), RVD10_4(10)

! Indexing variables
      INTEGER ICALL_NO                            ! Module call num
      INTEGER IT_0                                ! Storage Indices
      INTEGER ICX                                 ! Control/Monitoring
      INTEGER ISUBS, SS(1), IBRCH(1), INODE       ! SS/Node/Branch/Xfmr
      INTEGER IXFMR


!---------------------------------------
! Local Indices
!---------------------------------------


! Increment and assign runtime configuration call indices

      ICALL_NO  = NCALL_NO
      NCALL_NO  = NCALL_NO + 1

! Increment global storage indices

      ICX       = NCX
      NCX       = NCX + 1
      INODE     = NNODE + 2
      NNODE     = NNODE + 36
      IXFMR     = NXFMR
      NXFMR     = NXFMR + 3
      NCSCS     = NCSCS + 0
      NCSCR     = NCSCR + 0

! Initialize Subsystem Mapping

      ISUBS = NSUBS + 0
      NSUBS = NSUBS + 1

      DO IT_0 = 1,1
         SS(IT_0) = SUBS(ISUBS + IT_0)
      END DO

! Initialize Branch Mapping.

      IBRCH(1)     = NBRCH(SS(1))
      NBRCH(SS(1)) = NBRCH(SS(1)) + 49
!---------------------------------------
! Electrical Node Lookup
!---------------------------------------


! Array (1:3) quantities...
      DO IT_0 = 1,3
         NT_8(IT_0) = NODE(INODE + 22 + IT_0)
         NT_11(IT_0) = NODE(INODE + 31 + IT_0)
      END DO

!---------------------------------------
! Generated code from module definition
!---------------------------------------


! 60:[const] Real Constant 
      RT_6 = 1.0

! 140:[const] Real Constant 'VLL RMS'
      V_nom_con = 0.69

! 150:[const] Real Constant 'pu'
      Rs_pu = 0.0054

! 160:[const] Real Constant 'VLL RMS'
      V_nom_gen = 0.9

! 170:[const] Real Constant 'Turn Ratio'
      TRNR = 0.391

! 180:[const] Real Constant '[kV]'
      Vdc_Base = 1.45

! 190:[const] Real Constant 'maximum current of converters [pu]'
      I_max = 1.2

! 210:[LLTX_SCALER_Xpu]  

! 230:[xfmr-3p3w] 3 Phase 3 Winding Transformer 
      CALL COMPONENT_ID(ICALL_NO,468913194)
      RVD1_1 = ONE_3RD*Mrating
      RVD1_2 = VLL_Gr*SQRT_1BY3
      RVD1_3 = V_nom_con*SQRT_1BY3
      RVD1_4 = V_nom_gen*SQRT_1BY3
      CALL E_TF3W_CFG((IXFMR + 1),0,RVD1_1,freq,0.025,0.013,0.013,0.005,&
     &RVD1_2,RVD1_3,RVD1_4,2.0)
