     &1)+20), (IBRCH(1)+21),0,0,0,SS(1),RVD1_1,freq,0.025,0.013,0.013,0.&
     &0,0.0,0.0,RVD1_2,RVD1_3,RVD1_4,0.0,1.7,0.2,0.0,0.0,0.0,0.1,5.0e-5,&
     &2730.0,3209.0,20294.0,2.0,1.325e-5,0.96,1.72e6)

