      ENDIF
      RTCF(IVD1_1+2) = 0.02
      RTCF(IVD1_1+3) = 60.0

! 220:[multimeter] Multimeter 
      IVD1_1 = NRTCF
      NRTCF  = NRTCF + 5
      IF (ABS(1.0) .GT. 1.0E-20) THEN
        RTCF(IVD1_1) = 1.0/ABS(1.0)
      ELSE
        RTCF(IVD1_1) = 1.0
      ENDIF
      IF (ABS(VLL_Gr) .GT. 1.0E-20) THEN
        RTCF(IVD1_1+1) = 1.0/ABS(VLL_Gr)
      ELSE
        RTCF(IVD1_1+1) = 1.0
      ENDIF
