      CALL WindTurbine_MechModelOut_Begin(46.0, VRot_nom, 1.225, Pbase, &
     &vWcutin, vWcutout)


! 690:[DFIG_Converters_Avg]  
      CALL DFIG_Converters_AvgOut_Begin(Pbase, Mrating, 1, 300.0, freq, &
     &V_nom_con, 700.0, 350.0, 0.000621, 1.332, V_nom_gen, Rs_pu, Slip_m&
     &ax, TRNR, V_nom_con, Vdc_Base, 0.000192, 76.0, V_nom_con, 76.0)


      RETURN
